theory.syntax:
SELECT columns FROM table_name WHERE column_name IN (SELECT column_name FROM other_table);

SELECT columns FROM table_name AS t WHERE EXISTS (SELECT 1 FROM other_table WHERE condition);

SELECT columns FROM table_name WHERE column_name > ANY (SELECT column_name FROM other_table);

example.query:
-- 1. IN with a subquery
SELECT name FROM Students WHERE id IN (SELECT student_id FROM Enrollments WHERE course = 'DBMS');

-- 2. EXISTS checking for any enrollment at all
SELECT s.name FROM Students AS s WHERE EXISTS (SELECT 1 FROM Enrollments AS e WHERE e.student_id = s.id);

shared_table.create_sql:
CREATE TABLE Enrollments (
  id INTEGER PRIMARY KEY,
  student_id INTEGER,
  course TEXT
);
